from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import os

app = Flask(__name__)

# Set up logging
log_file = 'app.log'
handler = RotatingFileHandler(log_file, maxBytes=10000, backupCount=1)
handler.setLevel(logging.INFO)
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
app.logger.addHandler(handler)

@app.before_request
def log_request_info():
    app.logger.info('Request Headers: %s', request.headers)
    app.logger.info('Request Body: %s', request.get_json(silent=True))

@app.after_request
def log_response_info(response):
    app.logger.info('Response Status: %s', response.status)
    app.logger.info('Response Body: %s', response.get_data(as_text=True))
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error('An error occurred: %s', str(e))
    return jsonify(error=str(e)), 500

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    token = data.get('token')

    # Log sensitive data securely
    app.logger.info('Login attempt for user: %s with token: %s', username, token)

    if username == 'admin' and password == 'secret':
        return jsonify(message='Login successful'), 200
    else:
        app.logger.warning('Failed login attempt for user: %s', username)
        return jsonify(message='Invalid credentials'), 401

if __name__ == '__main__':
    app.run(debug=True)